solution_code:
#include <iostream>

void showDouble(int x)
{
    std::cout << x * 2 << "\n";
}

int addTen(int x)
{
    return x + 10;
}

int main()
{
    int a, b;
    std::cin >> a >> b;
    showDouble(a);
    showDouble(b);
    std::cout << addTen(a) << "\n";
    std::cout << addTen(b) << "\n";
    return 0;
}

